struct Value { enum Type {NIL, BOOL, NUMBER, STRING, ARRAY, OBJECT} type; bool b; double n; std::string s; std::vector<Value> a; std::map<std::string, Value> o; Value():type(NIL),b(false),n(0){} static Value boolean(bool v){Value x; x.type=BOOL; x.b=v; return x;} static Value number(double v){Value x; x.type=NUMBER; x.n=v; return x;} static Value str(const std::string& v){Value x; x.type=STRING; x.s=v; return x;} static Value array(){Value x; x.type=ARRAY; return x;} static Value object(){Value x; x.type=OBJECT; return x;} };
struct Block { std::string kind; std::string name; Value body; };
struct Token { std::string kind, text; size_t off; int line, col; };
static std::string esc(const std::string& in){std::ostringstream o; for(char c:in){switch(c){case '"':o<<"\\\"";break;case '\\':o<<"\\\\";break;case '\n':o<<"\\n";break;case '\r':o<<"\\r";break;case '\t':o<<"\\t";break;default: if((unsigned char)c<32)o<<"\\u00"<<std::hex<<std::setw(2)<<std::setfill('0')<<(int)(unsigned char)c<<std::dec; else o<<c;}}return o.str();}
static std::string json(const Value& v){std::ostringstream o; switch(v.type){case Value::NIL:o<<"null";break;case Value::BOOL:o<<(v.b?"true":"false");break;case Value::NUMBER: if(std::fabs(v.n-std::round(v.n))<1e-12) o<<std::fixed<<std::setprecision(0)<<v.n; else o<<std::setprecision(12)<<v.n; break;case Value::STRING:o<<'"'<<esc(v.s)<<'"';break;case Value::ARRAY:o<<"["; for(size_t i=0;i<v.a.size();++i){if(i)o<<","; o<<json(v.a[i]);} o<<"]";break;case Value::OBJECT:o<<"{"; {bool first=true; for(auto &kv:v.o){if(!first)o<<","; first=false; o<<'"'<<esc(kv.first)<<"\":"<<json(kv.second);} } o<<"}";break;} return o.str();}
static std::string pretty(const Value& v,int ind=0){ if(v.type!=Value::OBJECT && v.type!=Value::ARRAY) return json(v); std::ostringstream o; std::string pad(ind,' '), pad2(ind+2,' '); if(v.type==Value::ARRAY){o<<"["; for(size_t i=0;i<v.a.size();++i){o<<(i?",\n":"\n")<<pad2<<pretty(v.a[i],ind+2);} if(!v.a.empty()) o<<"\n"<<pad; o<<"]";} else {o<<"{"; bool first=true; for(auto &kv:v.o){o<<(first?"\n":",\n")<<pad2<<'"'<<esc(kv.first)<<"\": "<<pretty(kv.second,ind+2); first=false;} if(!v.o.empty()) o<<"\n"<<pad; o<<"}";} return o.str(); }

struct Parser { std::string text; std::vector<Token> toks; size_t p; Parser(const std::string&t):text(t),p(0){lex();}
 void lex(){int line=1,col=1; for(size_t i=0;i<text.size();){char c=text[i]; if(std::isspace((unsigned char)c)){ if(c=='\n'){line++;col=1;} else col++; i++; continue;} if(c=='#'){ while(i<text.size()&&text[i]!='\n'){i++;col++;} continue;} Token tok; tok.off=i; tok.line=line; tok.col=col; if(c=='"'){tok.kind="STRING"; i++; col++; std::ostringstream s; while(i<text.size()&&text[i]!='"'){ if(text[i]=='\\'&&i+1<text.size()){char e=text[++i]; if(e=='n')s<<'\n'; else if(e=='t')s<<'\t'; else s<<e; i++; col+=2;} else {s<<text[i++]; col++;}} if(i>=text.size()) throw err("unterminated string",tok); i++; col++; tok.text=s.str(); toks.push_back(tok); continue;} if(std::isdigit((unsigned char)c)||c=='-'){tok.kind="NUMBER"; size_t st=i; if(c=='-'){i++;col++;} while(i<text.size()&&(std::isdigit((unsigned char)text[i])||text[i]=='.')){i++;col++;} tok.text=text.substr(st,i-st); toks.push_back(tok); continue;} if(std::isalpha((unsigned char)c)||c=='_'){tok.kind="IDENT"; size_t st=i; while(i<text.size()&&(std::isalnum((unsigned char)text[i])||text[i]=='_'||text[i]=='-'||text[i]=='.')){i++;col++;} tok.text=text.substr(st,i-st); toks.push_back(tok); continue;} if(std::string("{}:[],").find(c)!=std::string::npos){tok.kind="PUNC"; tok.text=std::string(1,c); toks.push_back(tok); i++; col++; continue;} throw err("unexpected character",tok);} Token e; e.kind="EOF"; e.off=text.size(); e.line=line; e.col=col; toks.push_back(e);} 
 std::runtime_error err(const std::string&m,const Token&t){std::ostringstream o;o<<m<<" at line "<<t.line<<", column "<<t.col<<", byte "<<t.off;return std::runtime_error(o.str());}
 Token peek(){return toks[p];} Token adv(){return toks[p++];} void expect(const std::string&x){Token t=adv(); if(t.text!=x) throw err("expected '"+x+"', found '"+t.text+"'",t);} 
 std::vector<Block> parse(){std::vector<Block>b; while(peek().kind!="EOF") b.push_back(parseBlock()); return b;} Block parseBlock(){std::vector<std::string> h; while(peek().text!="{"){Token t=adv(); if(t.kind!="IDENT"&&t.kind!="STRING") throw err("expected block header",t); h.push_back(t.text);} expect("{"); Value body=parseBody(); expect("}"); Block b; for(size_t i=0;i+1<h.size();++i){ if(i)b.kind+="_"; b.kind+=h[i]; } if(h.size()==1)b.kind=h[0]; else b.name=h.back(); return b.body=body,b;}
 Value parseBody(){Value obj=Value::object(); while(peek().text!="}"){Token k=adv(); if(k.kind!="IDENT") throw err("expected key",k); if(peek().text==":"){adv(); obj.o[k.text]=parseValue();} else if(peek().text=="{"){adv(); obj.o[k.text]=parseBody(); expect("}");} else throw err("expected ':' or '{'",peek());} return obj;}
 Value parseValue(){Token t=adv(); if(t.kind=="STRING")return Value::str(t.text); if(t.kind=="NUMBER")return Value::number(std::strtod(t.text.c_str(),0)); if(t.kind=="IDENT"){if(t.text=="true")return Value::boolean(true); if(t.text=="false")return Value::boolean(false); return Value::str(t.text);} if(t.text=="["){Value a=Value::array(); if(peek().text!="]") while(true){a.a.push_back(parseValue()); if(peek().text!=",")break; adv();} expect("]"); return a;} if(t.text=="{"){Value o=parseBody(); expect("}"); return o;} throw err("unexpected value",t);} };
static std::vector<Block> loadManifest(const std::string& path){std::ifstream f(path.c_str()); if(!f) throw std::runtime_error("cannot open "+path); std::stringstream ss; ss<<f.rdbuf(); return Parser(ss.str()).parse();}
static std::map<std::string,std::vector<Block> > byKind(const std::vector<Block>&bs){std::map<std::string,std::vector<Block> > m; for(auto &b:bs)m[b.kind].push_back(b); return m;}
static Value emptyObj(){return Value::object();} static const Value* get(const Value& o,const std::string&k){auto it=o.o.find(k); return o.type==Value::OBJECT&&it!=o.o.end()?&it->second:0;} static Value firstBody(const std::map<std::string,std::vector<Block> >&m,const std::string&k){auto it=m.find(k); return it==m.end()?emptyObj():it->second[0].body;} static double num(const Value* v,double d=0){return !v?d:(v->type==Value::NUMBER?v->n:(v->type==Value::STRING?std::strtod(v->s.c_str(),0):d));} static std::string strv(const Value* v,const std::string&d=""){return !v?d:(v->type==Value::STRING?v->s:(v->type==Value::NUMBER?(static_cast<std::ostringstream&&>(std::ostringstream()<<v->n)).str():(v->type==Value::BOOL?(v->b?"true":"false"):d)));} static bool boolv(const Value* v,bool d=false){return !v?d:(v->type==Value::BOOL?v->b:d);} 
static Value blockArray(const std::map<std::string,std::vector<Block> >&m,const std::string&k){Value a=Value::array(); auto it=m.find(k); if(it!=m.end()) for(auto &b:it->second){Value o=b.body; if(!b.name.empty()) o.o["name"]=Value::str(b.name); a.a.push_back(o);} return a;}
static const std::set<std::string> MQ={"MQ0","MQ1","MQ2","MQ3","MQ4"}, DQ={"DQ0","DQ1","DQ2","DQ3","DQ4"};
static const std::map<std::string,std::pair<std::string,std::string> > budgetMap={{"energy_per_inference_j_max",{"energy_per_inference_j","J"}},{"energy_per_1000_inferences_wh_max",{"energy_per_1000_inferences_wh","Wh"}},{"energy_per_1000_tokens_wh_max",{"energy_per_1000_tokens_wh","Wh"}},{"training_energy_kwh_max",{"training_energy_kwh","kWh"}},{"fine_tuning_energy_kwh_max",{"fine_tuning_energy_kwh","kWh"}},{"evaluation_energy_kwh_max",{"evaluation_energy_kwh","kWh"}},{"carbon_per_1000_inferences_gco2e_max",{"carbon_per_1000_inferences_gco2e","gCO2e"}},{"carbon_per_1000_tokens_gco2e_max",{"carbon_per_1000_tokens_gco2e","gCO2e"}},{"carbon_per_training_run_kgco2e_max",{"carbon_per_training_run_kgco2e","kgCO2e"}},{"p95_latency_ms_max",{"p95_latency_ms","ms"}},{"p99_latency_ms_max",{"p99_latency_ms","ms"}},{"memory_peak_mb_max",{"memory_peak_mb","MB"}},{"gpu_memory_peak_mb_max",{"gpu_memory_peak_mb","MB"}},{"cpu_seconds_per_unit_max",{"cpu_seconds_per_unit","s"}},{"network_mb_per_task_max",{"network_mb_per_task","MB"}},{"storage_gb_month_max",{"storage_gb_month","GB-month"}},{"token_budget_per_task_max",{"tokens_per_task","tokens"}},{"retrieval_top_k_max",{"retrieval_top_k","documents"}},{"cross_region_transfer_gb_max",{"cross_region_transfer_gb","GB"}},{"update_payload_mb_max",{"update_payload_mb","MB"}},{"idle_overhead_watts_max",{"idle_overhead_watts","W"}},{"model_size_mb_max",{"model_size_mb","MB"}}};
static std::vector<std::string> energy={"training_energy_kwh","fine_tuning_energy_kwh","evaluation_energy_kwh","inference_energy_kwh","idle_energy_kwh","network_energy_kwh","storage_energy_kwh","client_energy_kwh","ci_cd_energy_kwh","update_energy_kwh","third_party_ai_api_energy_kwh"};
